+// --- Varint ---
+
+function readVarint(bytes: Uint8Array, pos: number): { value: number; bytesRead: number } {
+  let value = 0;
+  let shift = 0;
+  let bytesRead = 0;
+  while (pos + bytesRead < bytes.length) {
+    const b = bytes[pos + bytesRead];
+    value |= (b & 0x7f) << shift;
+    bytesRead++;
+    if ((b & 0x80) === 0) break;
+    shift += 7;
+  }
+  return { value, bytesRead };
+}
