+          for (let i = 0; i < decoded.length && values.length < numValues; i++) {
+            values.push(decoded[i]);
+          }
+        }
+      }
+
+      pos = pageDataEnd;
+      continue;
+    }
+
+    // Unknown page type — skip
+    pos = pageDataEnd;
+  }
+
+  return values;
